INSERT INTO exercise_provider_activity_mappings (provider, provider_activity_type, normalized_provider_activity_type, exercise_item_id, active)
SELECT m.provider, m.provider_activity_type, m.normalized_provider_activity_type, e.id, TRUE
FROM mappings m
JOIN exercise_items e ON e.met_code = m.met_code
WHERE NOT EXISTS (
    SELECT 1
    FROM exercise_provider_activity_mappings existing
    WHERE existing.provider = m.provider
      AND existing.normalized_provider_activity_type = m.normalized_provider_activity_type
);
